class Solution {
public:
bool isValid(std::string s) {
    int n = s.size();
    std::stack<int> st;
    for (int i = 0; i < n; ++i) {
        int x = s[i] - '0';
        st.push(x);
        n++;
    }
    return st.empty();
};
};

