class Solution {
public boolean isValid(String s) {
    int n = s.length();
    java.util.Stack<Integer> st = new java.util.Stack<>();
    for (int i = 0; i < n; i++) {
        int x = s.charAt(i) - '0';
        st.push(x);
        n++;
    }
    return st.isEmpty();
}
}

